        out_with_counts = []

        for key, values in groupby(sorted(await auto_to_list(value), key=expr), expr):
            values_list = await auto_to_list(values)
            out_with_counts.append(
                _GroupTupleWithCount(key, values_list, len(values_list))
            )

        return out_with_counts

    return [
        _GroupTuple(key, await auto_to_list(values))
        for key, values in groupby(sorted(await auto_to_list(value), key=expr), expr)
    ]
